    background: #e6fdf0;
    border-radius: 10px;
}

.gd_mainbase .customer-headersmall .profileicon.proj.tts_red .tits em.status {
    position: relative;
    background: none;
    font-size: 16px;
    border: none;
}



.remlogcont li {
    background: #f7f7f7;
    border-bottom: 1px solid #e9e9e9;
    list-style: none;
    margin: 0 0 2px 0;
    padding: 5px;
    font-size: 14px;
}

.remote-log-content {
    background-color: #f8f8f8;
    border-radius: 6px;
    padding: 15px;
    font-size: 14px;
    max-height: 300px;
    overflow-y: auto;
    white-space: pre-wrap;
    border: 1px solid #eeeeee;
    float: left;
    line-height: 25px;
}

.tab-btn.active {
    background: #4f46e5;
    color: #fff;
}

.sync-log-item.success {
    color: green;
}

.sync-log-item.error {
    color: red;
}

.sync-log-item.warning {
    color: orange;
}

.btn-run-schedule {
    background: #28a745;
    color: #fff;
    padding: 4px 10px;
    font-size: 12px;
}

.btn-run-schedule:hover {
    background: #218838;
}

.btn-table-action {
    border-radius: 4px;
}
</style>